ON CONFLICT DO NOTHING;

-- =========================================================================
-- RÉGUAS DE COBRANÇA (uma por empresa) + ETAPAS
-- =========================================================================

DO $$
DECLARE
  v_empresa RECORD;
  v_regua_id uuid;
  v_tpl_pre uuid; v_tpl_verde uuid; v_tpl_amarela uuid;
  v_tpl_laranja_a uuid; v_tpl_laranja_j uuid;
  v_tpl_vermelha_a uuid; v_tpl_vermelha_j uuid;
  v_tpl_roxa_m uuid; v_tpl_roxa_p uuid; v_tpl_preta uuid;
  v_tpl_whats uuid;
BEGIN
  SELECT id INTO v_tpl_pre FROM public.template_mensagem WHERE codigo = 'cobranca_pre_vencimento';
  SELECT id INTO v_tpl_verde FROM public.template_mensagem WHERE codigo = 'cobranca_faixa_verde';
  SELECT id INTO v_tpl_amarela FROM public.template_mensagem WHERE codigo = 'cobranca_faixa_amarela';
  SELECT id INTO v_tpl_laranja_a FROM public.template_mensagem WHERE codigo = 'cobranca_faixa_laranja_admin';
  SELECT id INTO v_tpl_laranja_j FROM public.template_mensagem WHERE codigo = 'cobranca_faixa_laranja_juridico';
  SELECT id INTO v_tpl_vermelha_a FROM public.template_mensagem WHERE codigo = 'cobranca_faixa_vermelha_admin';
  SELECT id INTO v_tpl_vermelha_j FROM public.template_mensagem WHERE codigo = 'cobranca_faixa_vermelha_juridico';
  SELECT id INTO v_tpl_roxa_m FROM public.template_mensagem WHERE codigo = 'cobranca_faixa_roxa_minuta';
  SELECT id INTO v_tpl_roxa_p FROM public.template_mensagem WHERE codigo = 'cobranca_faixa_roxa_parecer';
  SELECT id INTO v_tpl_preta FROM public.template_mensagem WHERE codigo = 'cobranca_faixa_preta';
  SELECT id INTO v_tpl_whats FROM public.template_mensagem WHERE codigo = 'cobranca_whatsapp_padrao';

  FOR v_empresa IN SELECT id, codigo FROM public.empresas WHERE codigo IN ('HAGG', 'SN', 'NH', 'CANAA')
  LOOP
    INSERT INTO public.regua_cobranca (empresa_id, nome, descricao, ativo, aplicar_para, valor_minimo)
    VALUES (v_empresa.id, 'Régua Padrão de Cobrança', 'Escalonamento administrativo e jurídico portado do sistema de cobranças', true, 'todos', 0)
    RETURNING id INTO v_regua_id;

    INSERT INTO public.regua_cobranca_etapa
      (regua_id, ordem, dias_em_relacao_vencimento, canal, template_id, setor_remetente, exige_aprovacao, ativo) VALUES
      (v_regua_id, 1,  -5,  'email',    v_tpl_pre,        'financeiro', false, true),
      (v_regua_id, 2,   1,  'email',    v_tpl_verde,       'financeiro', false, true),
      (v_regua_id, 3,  16,  'email',    v_tpl_amarela,     'financeiro', false, true),
      (v_regua_id, 4,  16,  'whatsapp', v_tpl_whats,       'financeiro', false, true),
      (v_regua_id, 5,  31,  'email',    v_tpl_laranja_a,   'financeiro', false, true),
      (v_regua_id, 6,  45,  'email',    v_tpl_laranja_j,   'juridico',   true,  true),
      (v_regua_id, 7,  61,  'email',    v_tpl_vermelha_a,  'financeiro', false, true),
      (v_regua_id, 8,  75,  'email',    v_tpl_vermelha_j,  'juridico',   true,  true),
      (v_regua_id, 9,  91,  'email',    v_tpl_roxa_m,      'juridico',   true,  true),
      (v_regua_id, 10, 92,  'email',    v_tpl_roxa_p,      'juridico',   true,  true),
      (v_regua_id, 11, 121, 'email',    v_tpl_preta,       'juridico',   true,  true);
  END LOOP;
END $$;
